<script setup lang="ts">
import{computed}from'vue';import{useQuery}from'@tanstack/vue-query';import{Activity,HardDrive,MemoryStick,Network,RefreshCw,Thermometer}from'lucide-vue-next';import Button from'@/components/ui/Button.vue';import StatusBadge from'@/components/ui/StatusBadge.vue';import{getHostTelemetry}from'@/lib/api';const query=useQuery({queryKey:['host-telemetry'],queryFn:getHostTelemetry,refetchInterval:10000});const hosts=computed(()=>{const grouped=new Map<string,{name:string;at:string;metrics:Record<string,number>}>();for(const metric of query.data.value??[]){const item=grouped.get(metric.host_id)??{name:metric.host_name,at:metric.captured_at,metrics:{}};item.metrics[metric.metric]=metric.value;if(metric.captured_at>item.at)item.at=metric.captured_at;grouped.set(metric.host_id,item)}return[...grouped.values()]});const gib=(value=0)=>(value/1073741824).toFixed(1)
</script><template><div class="mx-auto max-w-[1680px] space-y-5"><header class="flex items-end justify-between"><div><div class="flex items-center gap-2 font-mono text-[10px] uppercase tracking-widest text-signal"><Activity class="h-3.5 w-3.5"/>node_exporter + DCGM</div><h1 class="mt-3 text-3xl font-semibold tracking-tight">Telemetria dos hosts</h1><p class="mt-2 text-sm text-muted">Sinais Linux e NVIDIA recebidos por agentes autenticados.</p></div><Button variant="outline" @click="query.refetch()"><RefreshCw class="h-4 w-4"/>Atualizar</Button></header><section class="grid gap-4 xl:grid-cols-2"><article v-for="host in hosts" :key="host.name" class="rounded-xl border border-line bg-panel/65"><header class="flex items-center border-b border-line px-5 py-4"><div><h2 class="text-sm font-medium">{{host.name}}</h2><p class="mt-1 font-mono text-[9px] text-muted">{{new Date(host.at).toLocaleString('pt-BR')}}</p></div><StatusBadge class="ml-auto" status="healthy" label="transmitindo"/></header><div class="grid grid-cols-2 gap-px bg-line md:grid-cols-3"><div v-for="item in [{icon:Activity,label:'Carga 1 min',value:(host.metrics.node_load1??0).toFixed(2)},{icon:MemoryStick,label:'Memória disponível',value:gib(host.metrics.node_memory_MemAvailable_bytes)+' GiB'},{icon:HardDrive,label:'Sistema de arquivos disponível',value:gib(host.metrics.node_filesystem_avail_bytes)+' GiB'},{icon:Network,label:'RX total',value:gib(host.metrics.node_network_receive_bytes_total)+' GiB'},{icon:Network,label:'TX total',value:gib(host.metrics.node_network_transmit_bytes_total)+' GiB'},{icon:Thermometer,label:'Temperatura da GPU',value:(host.metrics.DCGM_FI_DEV_GPU_TEMP??0)+' °C'}]" :key="item.label" class="bg-panel p-4"><component :is="item.icon" class="h-3.5 w-3.5 text-muted"/><p class="mt-3 font-mono text-lg text-white">{{item.value}}</p><p class="mt-1 text-[10px] text-muted">{{item.label}}</p></div></div></article><div v-if="!hosts.length" class="col-span-full grid min-h-80 place-items-center rounded-xl border border-dashed border-line bg-panel/30 text-center"><div><Activity class="mx-auto h-7 w-7 text-muted"/><p class="mt-3 text-sm text-muted">Nenhum agente enviou métricas ainda.</p><p class="mt-1 text-xs text-slate-600">Provisione um token e inicie o perfil do agente.</p></div></div></section></div></template>

